1722	template <typename Func> void visit_interface_elements(const ast::PortConnection *conn, Func &&visit_fn)
1723	{
1724		assert(conn->getIfaceConn().second != nullptr);
1725		const ast::Symbol &if_instance = *conn->getIfaceConn().first;
1726		const ast::ModportSymbol &ref_modport = *conn->getIfaceConn().second;
1727		ast_invariant(if_instance, ast::InstanceArraySymbol::isKind(if_instance.kind) ||
1728						ast::InstanceSymbol::isKind(if_instance.kind));
1729	
1730		std::span<const slang::ConstantRange> array_range;
1731		if (ast::InstanceArraySymbol::isKind(if_instance.kind)) {
1732			auto range1 = conn->port.as<ast::InterfacePortSymbol>().getDeclaredRange();
1733			ast_invariant(conn->port, range1.has_value());
1734			array_range = range1.value();
1735		}
1736	
1737		std::string hierpath_suffix = "";
1738		int array_level = 0;
1739		if_instance.visit(ast::makeVisitor(
1740			[&](auto &visitor, const ast::InstanceArraySymbol &symbol) {
1741				// Mock instance array symbols made up by slang don't contain
1742				// the instances as members, but they do contain them as elements
1743				std::string save = hierpath_suffix;
1744				int i = 0;
1745				for (auto &elem : symbol.elements) {
1746					auto dim = array_range[array_level];
1747					int hdl_index = dim.lower() + i;
1748					i++;
1749					hierpath_suffix += "[" + std::to_string(hdl_index) + "]";
1750					array_level++;
