1757				// To support interface arrays, we need to match all modports
1758				// with the same name as ref_modport
1759				if (!modport.name.compare(ref_modport.name)) {
1760					visit_fn(modport, hierpath_suffix);
1761				}
1762			}
1763		));
1764	}
